def fibonacci(n):
    """Return the nth Fibonacci number (0-indexed). F(0)=0, F(1)=1."""
    if n <= 0:
        return 0
    if n == 1:
        return 1
    a, b = 0, 1
    for _ in range(n):  # Bug: should be range(n-1)
        a, b = b, a + b
    return b  # Bug: should return a (off by one)

